import{_ as t,o as i,c as s,ah as a}from"./chunks/framework.zwOixAa1.js";const k=JSON.parse('{"title":"Syntax & Types - v5","description":"Textwire has a simple syntax that is easy to learn","frontmatter":{"title":"Syntax & Types - v5","description":"Textwire has a simple syntax that is easy to learn"},"headers":[],"relativePath":"v5/language-elements/syntax.md","filePath":"versions/v5/language-elements/syntax.md","lastUpdated":1777824285000}'),o={name:"v5/language-elements/syntax.md"};function d(n,e,l,r,c,h){return i(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="syntax-types" tabindex="-1">Syntax &amp; Types <a class="header-anchor" href="#syntax-types" aria-label="Permalink to &quot;Syntax &amp; Types&quot;">​</a></h1><p>Textwire’s syntax is straightforward and easy to learn. Below are the key rules for writing Textwire code:</p><ul><li><strong>File Extensions:</strong> All HTML files intended for Textwire parsing must have a <code>.tw</code> extension.</li><li><strong>Code Placement:</strong> All Textwire code must either: <ul><li>Be enclosed within <code>{{ }}</code> braces, or</li><li>Be enclosed within <code>{!! !!}</code> braces, or</li><li>Start with the <code>@</code> symbol.</li></ul></li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">Syntax Highlighting</p><p>If you use Neovim or VSCode, you can use our <a href="https://github.com/textwire/textwire.nvim" target="_blank" rel="noreferrer">Neovim plugin</a> or <a href="https://marketplace.visualstudio.com/items?itemName=SerhiiCho.textwire" target="_blank" rel="noreferrer">VSCode extension</a> to get syntax highlighting and other features for Textwire.</p></div><h2 id="directives" tabindex="-1">Directives <a class="header-anchor" href="#directives" aria-label="Permalink to &quot;Directives&quot;">​</a></h2><p>Directives are Textwire statements that begin with the <code>@</code> symbol. They define layouts, insert content into placeholders, and perform logical operations like conditionals and loops. Directives can only be placed within HTML and cannot be used inside braces (<code>{{</code> and <code>}}</code>).</p><h3 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h3><ul><li><strong>Expressions and Variables</strong>: Directives support expressions and variables, such as <code>@if(x == 1)</code> or <code>@use(layoutName)</code>.</li><li><strong>Closing Directives</strong>: Directives with a body (like <code>@if</code>, <code>@for</code>, <code>@each</code>, and <code>@component</code>) must be closed with the <code>@end</code> keyword.</li></ul><p>Read about directives on <a href="/v5/language-elements/directives">Directives</a> page.</p><h2 id="escaping" tabindex="-1">Escaping <a class="header-anchor" href="#escaping" aria-label="Permalink to &quot;Escaping&quot;">​</a></h2><p>Escape Textwire code by prefixing it with a backslash (<code>\\</code>). For example:</p><div class="language-textwire vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textwire</span><pre class="shiki shiki-themes github-light catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#CDD6F4;">\\{{ not code }}</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#CDD6F4;">\\@use(&quot;~base&quot;)</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span></span></code></pre></div><p>will be rendered as:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#CDD6F4;">{{ not code }}</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#CDD6F4;">@use(&quot;~base&quot;)</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#89B4FA;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#94E2D5;">&gt;</span></span></code></pre></div><h2 id="raw-unescaped-output" tabindex="-1">Raw Unescaped Output <a class="header-anchor" href="#raw-unescaped-output" aria-label="Permalink to &quot;Raw Unescaped Output&quot;">​</a></h2><p>All of your outputs in Textwire using <code>{{ }}</code> are HTML-encoded. But there are cases when you want to output raw HTML, XML or JSON. To do that, you can use the <code>{!! !!}</code> braces. For example:</p><div class="language-textwire vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textwire</span><pre class="shiki shiki-themes github-light catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">{!!</span><span style="--shiki-light:#032F62;--shiki-dark:#A6E3A1;"> &quot;&lt;p&gt;This is raw, unescaped HTML&lt;/p&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> !!}</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-light-font-style:inherit;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">{{-- Output: &lt;p&gt;This is raw, unescaped HTML&lt;/p&gt; --}}</span></span></code></pre></div><h2 id="embedded" tabindex="-1">Embedded <a class="header-anchor" href="#embedded" aria-label="Permalink to &quot;Embedded&quot;">​</a></h2><p>Embedded code begins with <code>{{</code> and end with <code>}}</code>. It is used for defining variables, performing arithmetic operations, conditionally rendering content, and more. Embedded code can be placed anywhere in the file, except within directives.</p><h3 id="important-notes-1" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes-1" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h3><ul><li><p><strong>Multiple Expressions</strong>: Use a semicolon (<code>;</code>) to separate multiple statements/expressions inside braces. For example:</p><div class="language-textwire vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">textwire</span><pre class="shiki shiki-themes github-light catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">{{</span><span style="--shiki-light:#24292E;--shiki-dark:#CBA6F7;"> x</span><span style="--shiki-light:#D73A49;--shiki-dark:#CBA6F7;"> = </span><span style="--shiki-light:#005CC5;--shiki-dark:#FAB387;">5</span><span style="--shiki-light:#D73A49;--shiki-dark:#CBA6F7;">; </span><span style="--shiki-light:#24292E;--shiki-dark:#CBA6F7;">x</span><span style="--shiki-light:#D73A49;--shiki-dark:#CBA6F7;">++; </span><span style="--shiki-light:#24292E;--shiki-dark:#CBA6F7;">x</span><span style="--shiki-light:#005CC5;--shiki-light-font-style:inherit;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> }}</span></span></code></pre></div></li><li><p><strong>Return Values</strong>: All embedded code returns a string.</p></li><li><p>Defining a variable like <code>{{ x = 5 }}</code> doesn&#39;t return anything.</p></li><li><p>Expressions like <code>{{ 5 + 5 }}</code> will return a result. In this case, it&#39;s <code>&quot;10&quot;</code>.</p></li></ul><h2 id="types-and-literals" tabindex="-1">Types and Literals <a class="header-anchor" href="#types-and-literals" aria-label="Permalink to &quot;Types and Literals&quot;">​</a></h2><p>Textwire has a different type system from Go. When you pass a variable to Textwire, it will be automatically converted to a Textwire type. Here is a list of supported types that you can pass to Textwire or define in Textwire:</p><table tabindex="0"><thead><tr><th>Textwire type</th><th>Equivalent Go types</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>string</code></td></tr><tr><td><code>boolean</code></td><td><code>bool</code></td></tr><tr><td><code>integer</code></td><td><code>int</code>, <code>int8</code>, <code>int16</code>, <code>int32</code>, <code>int64</code>, <code>uint</code>, <code>uint8</code>, <code>uint16</code>, <code>uint32</code>, <code>uint64</code></td></tr><tr><td><code>float</code></td><td><code>float32</code>, <code>float64</code></td></tr><tr><td><code>nil</code></td><td><code>nil</code></td></tr><tr><td><code>array</code></td><td><code>[]string</code>, <code>[]bool</code>, <code>[]int</code>, <code>[]int64</code>, <code>[]int32</code>, <code>[]int16</code>, <code>[]int8</code>, <code>[]uint</code>, <code>[]uint64</code>, <code>[]uint32</code>, <code>[]uint16</code>, <code>[]uint8</code>, <code>[]float64</code>, <code>[]float32</code></td></tr><tr><td><code>object</code></td><td><code>struct{}</code>, <code>User{}</code>, <code>map[string]string</code>, any struct or map</td></tr></tbody></table><p>The biggest difference in types and type literals between Textwire and Go is that Textwire&#39;s literals have functions that you can call on them. For example, you can call a <code>split</code> function on a string literal like this: <code>{{ &quot;hello world&quot;.split(&quot; &quot;) }}</code> to get an array of strings <code>[&quot;hello&quot;, &quot;world&quot;]</code>.</p><h2 id="nullable-types" tabindex="-1">Nullable Types <a class="header-anchor" href="#nullable-types" aria-label="Permalink to &quot;Nullable Types&quot;">​</a></h2><p>Like Go, each type in Textwire has a nullable version. Here is the table of nullable types:</p><table tabindex="0"><thead><tr><th>Type</th><th>Empty Literal</th><th>Description</th></tr></thead><tbody><tr><td><code>string</code></td><td><code>&quot;&quot;</code></td><td>Empty string</td></tr><tr><td><code>integer</code></td><td><code>0</code>, <code>-0</code></td><td>Zero integer</td></tr><tr><td><code>float</code></td><td><code>0.0</code>, <code>-0.0</code></td><td>Zero float</td></tr><tr><td><code>boolean</code></td><td><code>false</code></td><td>False boolean</td></tr><tr><td><code>array</code></td><td><code>[]</code></td><td>Empty array</td></tr><tr><td><code>object</code></td><td><code>{}</code></td><td>Empty object</td></tr><tr><td><code>nil</code></td><td><code>nil</code></td><td>Nil value</td></tr></tbody></table>`,28)])])}const u=t(o,[["render",d]]);export{k as __pageData,u as default};
